async function seed() {
  const conn = await mysql.createConnection(DB_URL);
  console.log(`Seeding ${resources.length} county resources...`);
  let inserted = 0;
  for (const r of resources) {
    try {
      await conn.execute(
        `INSERT INTO county_resources (name, county, category, subCategory, description, address, city, state, zipCode, phone, website, hours, eligibility, walkInsWelcome, appointmentRequired, acceptingClients, hasWaitlist, freeService, ecmEligible, mediCalAccepted, slidingScale, isVerified, isActive)
         VALUES (?, ?, ?, ?, ?, ?, ?, 'CA', ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, 1)`,
        [r.name, r.county, r.category, r.subCategory || null, r.description || null,
         r.address || null, r.city || null, r.zipCode || null, r.phone || null,
         r.website || null, r.hours || null, r.eligibility || null,
         r.walkInsWelcome ? 1 : 0, r.appointmentRequired ? 1 : 0,
         r.acceptingClients ? 1 : 0, r.hasWaitlist ? 1 : 0,
         r.freeService ? 1 : 0, r.ecmEligible ? 1 : 0,
         r.mediCalAccepted ? 1 : 0, r.slidingScale ? 1 : 0]
      );
      inserted++;
    } catch (e) {
      console.error(`Failed: ${r.name}`, e.message);
    }
  }
  console.log(`Done. Inserted ${inserted}/${resources.length} resources.`);
  await conn.end();
}

seed().catch(console.error);
